'use client';

import { useCallback, useMemo, useState } from "react";

import type { ReportRecord, ReportStatus } from "@/types/domain";

const createdAtFormatter = new Intl.DateTimeFormat("ro-RO", {
  dateStyle: "medium",
  timeStyle: "short"
});

const statusOrder: ReportStatus[] = ["NEW", "IN_PROGRESS", "RESOLVED", "REJECTED"];

export function formatStatus(status: ReportStatus) {
  switch (status) {
    case "NEW":
      return "Nouă";
    case "IN_PROGRESS":
      return "În lucru";
    case "RESOLVED":
      return "Rezolvată";
    case "REJECTED":
      return "Respinsă";
    default:
      return status;
  }
}

const statusStyles: Record<ReportStatus, { badge: string; dot: string; hint: string }> = {
  NEW: { badge: "bg-gray-200 text-gray-800", dot: "bg-gray-400", hint: "Nu apare pe harta publică" },
  IN_PROGRESS: { badge: "bg-amber-100 text-amber-800", dot: "bg-amber-500", hint: "Vizibil pe hartă" },
  RESOLVED: { badge: "bg-emerald-100 text-emerald-800", dot: "bg-emerald-500", hint: "Vizibil pe hartă" },
  REJECTED: { badge: "bg-rose-100 text-rose-800", dot: "bg-rose-500", hint: "Nu apare pe harta publică" }
};

type AdminDashboardProps = {
  reports: ReportRecord[];
  isLoading: boolean;
  error?: string | null;
  onStatusChange: (reportId: number, nextStatus: ReportStatus, note?: string) => Promise<void>;
};

export function AdminDashboard({ reports, isLoading, error, onStatusChange }: AdminDashboardProps) {
  const [localPending, setLocalPending] = useState<Record<number, boolean>>({});
  const markerHint = useMemo(
    () => "Marcajul apare pe harta publică doar pentru rapoartele În lucru sau Rezolvate.",
    []
  );

  const handleStatusChange = useCallback(
    async (reportId: number, nextStatus: ReportStatus) => {
      setLocalPending((prev) => ({ ...prev, [reportId]: true }));
      try {
        await onStatusChange(reportId, nextStatus);
      } finally {
        setLocalPending((prev) => {
          const next = { ...prev };
          delete next[reportId];
          return next;
        });
      }
    },
    [onStatusChange]
  );

  return (
    <div className="w-full px-4 py-8 sm:px-6 lg:px-8">
      <div className="mx-auto flex w-full max-w-6xl flex-col gap-6">
        <header className="flex flex-col gap-2">
          <p className="text-sm font-semibold uppercase tracking-[0.2em] text-slate-500">
            Admin / Triage Dashboard
          </p>
          <div className="flex flex-col gap-3 rounded-3xl bg-white/90 p-6 shadow-lg shadow-slate-100">
            <div className="flex flex-wrap items-start justify-between gap-4">
              <h1 className="text-2xl font-semibold text-slate-900">Rapoarte comunitare</h1>
              <span className="text-sm font-medium text-slate-500">{markerHint}</span>
            </div>
            <div className="flex flex-wrap gap-3 text-xs text-slate-500">
              {statusOrder.map((status) => {
                const meta = statusStyles[status];
                return (
                  <div key={status} className="flex items-center gap-2 rounded-full bg-slate-100 px-3 py-1">
                    <span className={`h-2 w-2 rounded-full ${meta.dot}`} />
                    <span className="font-semibold text-slate-700">{formatStatus(status)}</span>
                    <span className="text-slate-400">{meta.hint}</span>
                  </div>
                );
              })}
            </div>
          </div>
        </header>

        {error ? (
          <div className="rounded-2xl border border-rose-200 bg-rose-50 p-4 text-rose-700">
            {error}
          </div>
        ) : null}

        {isLoading ? (
          <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
            {Array.from({ length: 6 }).map((_, index) => (
              <div
                key={`skeleton-${index}`}
                className="h-56 animate-pulse rounded-3xl bg-white/60 p-6 shadow-lg shadow-slate-100"
              >
                <div className="h-4 w-3/4 rounded-full bg-slate-200" />
                <div className="mt-4 h-3 w-full rounded-full bg-slate-100" />
                <div className="mt-2 h-3 w-5/6 rounded-full bg-slate-100" />
              </div>
            ))}
          </div>
        ) : null}

        {!isLoading && !reports.length ? (
          <div className="rounded-3xl border border-dashed border-slate-200 bg-white/60 p-10 text-center text-slate-500">
            Nu există rapoarte de afișat. Încearcă să reîmprospătezi sau verifică mai târziu.
          </div>
        ) : null}

        <section className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
          {reports.map((report) => {
            const meta = statusStyles[report.status];
            const isUpdating = Boolean(localPending[report.id]);
            return (
              <article
                key={report.id}
                className="flex flex-col gap-4 rounded-3xl bg-white p-6 shadow-lg shadow-slate-100 transition hover:-translate-y-0.5 hover:shadow-xl"
              >
                <div className="flex items-start justify-between gap-4">
                  <div>
                    <h2 className="text-base font-semibold text-slate-900">{report.title}</h2>
                    <p className="text-xs text-slate-400">
                      Creat {createdAtFormatter.format(new Date(report.createdAt))}
                    </p>
                    {report.user ? (
                      <p className="text-xs text-slate-400">
                        Raportat de {report.user.firstName} {report.user.lastName}
                      </p>
                    ) : null}
                  </div>
                  <span className={`flex items-center gap-2 rounded-full px-3 py-1 text-xs font-semibold ${meta.badge}`}>
                    <span className={`h-2 w-2 rounded-full ${meta.dot}`} />
                    {formatStatus(report.status)}
                  </span>
                </div>

                {report.description ? (
                  <p className="text-sm text-slate-600">{report.description}</p>
                ) : (
                  <p className="text-sm text-slate-400 italic">Fără descriere detaliată</p>
                )}

                <div className="flex flex-wrap gap-3 text-xs text-slate-500">
                  {report.category?.name ? (
                    <span className="rounded-full bg-slate-100 px-3 py-1">{report.category.name}</span>
                  ) : null}
                  {report.city?.name ? (
                    <span className="rounded-full bg-slate-100 px-3 py-1">{report.city.name}</span>
                  ) : null}
                  {report.user ? (
                    <span className="rounded-full bg-slate-50 px-3 py-1">
                      Utilizator: {report.user.email}
                    </span>
                  ) : null}
                  <span className="rounded-full bg-slate-50 px-3 py-1">{meta.hint}</span>
                </div>

                <label className="flex flex-col gap-2 text-sm font-medium text-slate-900">
                  Actualizează statusul
                  <select
                    className="rounded-2xl border border-slate-200 bg-slate-50 px-4 py-2 text-sm font-medium text-slate-900 focus:border-slate-400 focus:outline-none"
                    value={report.status}
                    onChange={(event) => handleStatusChange(report.id, event.target.value as ReportStatus)}
                    disabled={isUpdating}
                  >
                    {statusOrder.map((status) => (
                      <option key={status} value={status}>
                        {formatStatus(status)}
                      </option>
                    ))}
                  </select>
                </label>

                <div className="flex flex-wrap gap-3">
                  <button
                    type="button"
                    className="rounded-2xl bg-emerald-100 px-4 py-2 text-sm font-semibold text-emerald-700 transition hover:bg-emerald-200 disabled:cursor-not-allowed disabled:opacity-60"
                    onClick={() => handleStatusChange(report.id, "IN_PROGRESS")}
                    disabled={isUpdating}
                  >
                    Aprobă
                  </button>
                  <button
                    type="button"
                    className="rounded-2xl bg-rose-100 px-4 py-2 text-sm font-semibold text-rose-700 transition hover:bg-rose-200 disabled:cursor-not-allowed disabled:opacity-60"
                    onClick={() => handleStatusChange(report.id, "REJECTED")}
                    disabled={isUpdating}
                  >
                    Respinge
                  </button>
                </div>

                {isUpdating ? <p className="text-xs font-medium text-amber-700">Se sincronizează...</p> : null}
              </article>
            );
          })}
        </section>
      </div>
    </div>
  );
}
