'use client';

import { useCallback, useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import type { Route } from "next";

import { AdminDashboard } from "@/components/AdminDashboard";
import { useAuth } from "@/context/AuthContext";
import { fetchAdminReports, updateReportStatus } from "@/lib/api";
import type { ReportRecord, ReportStatus, Role } from "@/types/domain";

const allowedRoles: Role[] = ["ADMIN", "MODERATOR"];

export default function AdminPage() {
  const router = useRouter();
  const { user, isReady } = useAuth();
  const token = user?.token;

  const [reports, setReports] = useState<ReportRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!isReady) return;
    if (!user || !token || !allowedRoles.includes(user.role)) {
      router.replace("/" as Route);
    }
  }, [isReady, user, token, router]);

  const loadReports = useCallback(async () => {
    if (!token) {
      setIsLoading(false);
      return;
    }
    setIsLoading(true);
    setError(null);
    try {
      const data = await fetchAdminReports(token);
      setReports(data);
    } catch (err) {
      const message = err instanceof Error ? err.message : "Nu am putut încărca rapoartele";
      setError(message);
    } finally {
      setIsLoading(false);
    }
  }, [token]);

  useEffect(() => {
    if (!token) return;
    void loadReports();
  }, [token, loadReports]);

  const handleStatusChange = useCallback(
    async (reportId: number, nextStatus: ReportStatus) => {
      if (!token) return;
      await updateReportStatus(reportId, nextStatus, token);
      await loadReports();
    },
    [token, loadReports]
  );

  return (
    <main className="relative min-h-screen overflow-hidden bg-gradient-to-b from-[#eff6ff] via-[#f5f9ff] to-surface">
      <div className="pointer-events-none absolute inset-0">
        <div className="absolute -left-12 top-16 h-64 w-64 rounded-full bg-[#c6d9ff] opacity-40 blur-[120px]" />
        <div className="absolute right-4 top-40 h-80 w-80 rounded-full bg-[#ffd39a] opacity-30 blur-[140px]" />
        <div className="absolute bottom-0 left-1/4 h-72 w-72 rounded-full bg-[#a7f3d0] opacity-30 blur-[160px]" />
      </div>
      <div className="relative z-10 mx-auto flex w-full max-w-7xl flex-col gap-8 py-10">
        <div className="flex flex-wrap items-center justify-between gap-4 px-6">
          <div>
            <p className="text-sm font-semibold uppercase tracking-[0.3em] text-slate-500">
              CitySafe Control Room
            </p>
            <h1 className="mt-2 text-3xl font-bold text-slate-900 md:text-4xl">
              Monitorizează rapoartele și gestionează prezența lor pe hartă
            </h1>
          </div>
          <button
            type="button"
            onClick={() => void loadReports()}
            className="rounded-full border border-slate-200 px-5 py-2 text-sm font-semibold text-slate-700 transition hover:border-slate-400"
            disabled={isLoading}
          >
            Reîmprospătează
          </button>
        </div>
        <section className="rounded-[32px] bg-white/70 px-2 py-4 shadow-card backdrop-blur">
          <AdminDashboard
            reports={reports}
            isLoading={isLoading}
            error={error}
            onStatusChange={handleStatusChange}
          />
        </section>
      </div>
    </main>
  );
}
